def depth_max(s):
    max_depth = 0
    current_depth = 0

    for char in s:
        if char == '[':
            current_depth += 1
            max_depth = max(max_depth, current_depth)
        elif char == ']':
            current_depth -= 1
            if current_depth < 0:
                return -1

    if current_depth != 0:
        return -1

    return max_depth if max_depth > 0 else 0
